<?php
namespace App\Services;
use App\Mail\DonationVerifiedMail; use App\Models\Campaign; use App\Models\Donation; use Illuminate\Support\Facades\DB; use Illuminate\Support\Facades\Mail;
class DonationService { public function store(Campaign $campaign, array $data, ?int $userId): Donation { return DB::transaction(function() use($campaign,$data,$userId){ $proof=$data['proof']; $donation=Donation::create(['campaign_id'=>$campaign->id,'donor_id'=>$userId,'donor_name'=>$data['donor_name'],'donor_email'=>$data['donor_email'],'amount'=>$data['amount'],'message'=>$data['message'] ?? null,'status'=>'waiting']); $donation->proof()->create(['bank_name'=>$data['bank_name'],'account_name'=>$data['account_name'],'transfer_date'=>$data['transfer_date'],'file_path'=>$proof->store('donation-proofs','public'),'original_name'=>$proof->getClientOriginalName(),'mime_type'=>$proof->getClientMimeType(),'file_size'=>$proof->getSize()]); return $donation; }); } public function verify(Donation $donation, array $data, int $adminId, ?string $ip, ?string $ua): Donation { return DB::transaction(function() use($donation,$data,$adminId,$ip,$ua){ $approved=$data['action']==='approve'; if ($approved && $donation->status !== 'verified') $donation->campaign()->increment('collected_amount',$donation->amount); if (!$approved && $donation->status === 'verified') $donation->campaign()->decrement('collected_amount',$donation->amount); $donation->update(['status'=>$approved?'verified':'rejected','verified_by'=>$adminId,'verified_at'=>now(),'admin_notes'=>$data['admin_notes'] ?? null]); $donation->verificationLogs()->create(['admin_id'=>$adminId,'action'=>$approved?'approved':'rejected','notes'=>$data['admin_notes'] ?? null,'ip_address'=>$ip,'user_agent'=>$ua]); if ($approved) Mail::to($donation->donor_email)->queue(new DonationVerifiedMail($donation)); return $donation; }); } }
